\displaystyle{\begin{aligned}
  \frac{{\frac{1}{m-4}+\frac{2}{m-4}}}{{5-\frac{1}{m+4}}} \amp = \frac{({\frac{1}{m-4}+\frac{2}{m-4}})\cdot{\left(m+4\right)\mathopen{}\left(m-4\right)}}{({5-\frac{1}{m+4}})\cdot{\left(m+4\right)\mathopen{}\left(m-4\right)}} \\
    \amp = \frac{{\frac{1}{m-4}\mathopen{}\left(m+4\right)\mathopen{}\left(m-4\right)+\frac{2}{m-4}\mathopen{}\left(m+4\right)\mathopen{}\left(m-4\right)}}{{5\mathopen{}\left(m+4\right)\mathopen{}\left(m-4\right)-\frac{1}{m+4}\mathopen{}\left(m+4\right)\mathopen{}\left(m-4\right)}} \\
    \amp = \frac{{m+4+2\mathopen{}\left(m+4\right)}}{{5\mathopen{}\left(m^{2}-16\right)-\left(m-4\right)}}, m \ne 4 \text{ and }  m \ne -4 \\
    \amp = \frac{{m+4+2m+8}}{{5m^{2}-80-m+4}}, m \ne 4 \text{ and }  m \ne -4 \\
    \amp = \frac{{3m+12}}{{5m^{2}-m-76}}, m \ne 4 \text{ and }  m \ne -4 \\
    \amp = {\frac{3\mathopen{}\left(m+4\right)}{\left(5m+19\right)\mathopen{}\left(m-4\right)}, m\ne -4}
\end{aligned}
